```javascript
function aplanarArray(array) {
  let resultado = [];
  for (let i = 0; i < array.length; i++) {
    if (Array.isArray(array[i])) {
      // Si es array, concatenamos sus elementos
      resultado = resultado.concat(array[i]);
    } else {
      // Si no, lo añadimos directamente
      resultado.push(array[i]);
    }
  }
  return resultado;
}

// Versión con reduce:
function aplanarArray(array) {
  return array.reduce((acc, elem) => {
    return acc.concat(Array.isArray(elem) ? elem : [elem]);
  }, []);
}

// Versión con flat (ES2019):
const aplanarArray = arr => arr.flat();
```

**Explicación:**
- `Array.isArray()` comprueba si un valor es un array
- `.concat()` une arrays sin mutar el original
- `.flat()` hace esto automáticamente pero solo es ES2019+

```javascript
function crearContador(boton) {
  let contador = 0;
  boton.textContent = 'Clics: 0';

  boton.addEventListener('click', function() {
    contador++;
    this.textContent = 'Clics: ' + contador;
  });
}

// Versión con arrow function (no usar this):
