```javascript
function Calculadora() {}

Calculadora.prototype.sumar = function(a, b) {
  return a + b;
};

Calculadora.prototype.dividir = function(a, b) {
  return a / b;
};

// Versión con clase moderna ES6:
class Calculadora {
  sumar(a, b) { return a + b; }
  dividir(a, b) { return a / b; }
}

// --- Tests ---

function testearCalculadora() {
  const calc = new Calculadora();
  let pasados = 0;
  let fallados = 0;

  // Helper para ejecutar un test
  function test(nombre, resultadoEsperado, fn) {
    try {
      const resultado = fn();
      if (resultado === resultadoEsperado) {
        console.log('✅ PASS - ' + nombre);
        pasados++;
      } else {
        console.error('❌ FAIL - ' + nombre);
        console.error('   Esperado: ' + resultadoEsperado + ', Obtenido: ' + resultado);
        fallados++;
      }
    } catch (error) {
      console.error('❌ ERROR - ' + nombre);
      console.error('   Excepción: ' + error.message);
      fallados++;
    }
  }

  // Test 1: sumar(2, 3) = 5
  test('sumar(2, 3) = 5', 5, () => calc.sumar(2, 3));

  // Test 2: sumar(-1, 1) = 0
  test('sumar(-1, 1) = 0', 0, () => calc.sumar(-1, 1));

  // Test 3: dividir(10, 2) = 5
  test('dividir(10, 2) = 5', 5, () => calc.dividir(10, 2));

  // Test 4: dividir(5, 0) = Infinity
  test('dividir(5, 0) = Infinity', Infinity, () => calc.dividir(5, 0));

  // Resumen
  console.log('---');
  console.log(`Total: ${pasados + fallados} | ✅ ${pasados} | ❌ ${fallados}`);
}

// Ejecutar
testearCalculadora();

// Versión más simple con console.assert:
function testearCalculadoraSimple() {
  const calc = new Calculadora();

  console.assert(calc.sumar(2, 3) === 5, 'sumar(2, 3) debería ser 5');
  console.assert(calc.sumar(-1, 1) === 0, 'sumar(-1, 1) debería ser 0');
  console.assert(calc.dividir(10, 2) === 5, 'dividir(10, 2) debería ser 5');
  console.assert(calc.dividir(5, 0) === Infinity, 'dividir(5, 0) debería ser Infinity');

  console.log('Tests completados (revisa la consola para ver fallos)');
}
```

**Diferencias clave con Java:**
- **Java:** `5 / 0` lanza `ArithmeticException`. Hay que esperar la excepción con `assertThrows`
- **JavaScript:** `5 / 0` devuelve `Infinity`. No hay excepción, se comprueba el valor
- `console.assert()` es el equivalente más directo a `assertEquals()` pero solo muestra error si falla, no interrumpe el flujo
- El patrón de la función  con helper
   y contadores es un mini-test-runner casero,
  similar a Jest pero sin dependencias externas. `testearCalculadora` con helper `test()` y contadores es un mini-test-runner casero, similar a cómo funciona JUnit por debajo

